+    // peek() returns current char (the '0'), peekAhead(1) returns next char (the prefix)
+    if (self.peek() == '0' and self.peekAhead(1) != null) {
+        const prefix = self.peekAhead(1).?;
+        if (prefix == 'x' or prefix == 'X') {
+            // Hexadecimal: 0x...
+            _ = self.advance(); // consume '0'
+            _ = self.advance(); // consume 'x' or 'X'
+            while (self.peek()) |c| {
+                if (isHexDigit(c)) {
+                    _ = self.advance();
+                } else {
+                    break;
+                }
+            }
+            const lexeme = self.source[start..self.current];
+            return Token{
+                .type = .Number,
+                .lexeme = lexeme,
+                .line = self.line,
+                .column = start_column,
+            };
+        } else if (prefix == 'o' or prefix == 'O') {
+            // Octal: 0o...
+            _ = self.advance(); // consume '0'
+            _ = self.advance(); // consume 'o' or 'O'
+            while (self.peek()) |c| {
+                if (c >= '0' and c <= '7') {
+                    _ = self.advance();
+                } else {
+                    break;
+                }
+            }
+            const lexeme = self.source[start..self.current];
+            return Token{
+                .type = .Number,
+                .lexeme = lexeme,
+                .line = self.line,
+                .column = start_column,
+            };
+        } else if (prefix == 'b' or prefix == 'B') {
+            // Binary: 0b...
+            _ = self.advance(); // consume '0'
+            _ = self.advance(); // consume 'b' or 'B'
+            while (self.peek()) |c| {
+                if (c == '0' or c == '1') {
+                    _ = self.advance();
+                } else {
+                    break;
+                }
+            }
+            const lexeme = self.source[start..self.current];
+            return Token{
+                .type = .Number,
+                .lexeme = lexeme,
+                .line = self.line,
+                .column = start_column,
+            };
+        }
+    }
+
+    // Decimal number
+    while (self.peek()) |c| {
+        if (self.isDigit(c)) {
+            _ = self.advance();
+        } else {
+            break;
+        }
+    }
+
+    // Handle decimal point
+    if (self.peek() == '.' and self.peekAhead(1) != null) {
+        const next = self.peekAhead(1).?;
+        if (self.isDigit(next)) {
+            _ = self.advance(); // consume '.'
+            while (self.peek()) |c| {
+                if (self.isDigit(c)) {
+                    _ = self.advance();
+                } else {
+                    break;
+                }
+            }
+        }
+    }
+
+    // Handle complex number suffix 'j' or 'J'
+    const is_complex = if (self.peek()) |c| (c == 'j' or c == 'J') else false;
+    if (is_complex) {
+        _ = self.advance(); // consume 'j' or 'J'
+    }
+
+    const lexeme = self.source[start..self.current];
+    return Token{
+        .type = if (is_complex) .ComplexNumber else .Number,
+        .lexeme = lexeme,
+        .line = self.line,
+        .column = start_column,
+    };
